using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL
            // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') still work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 maps Id directly to JSON "id" without a discriminator prefix.
            // Existing documents store id as "Blog|{key}"; use a value converter
            // to preserve that format.
            entity.Property(b => b.Id).HasConversion(
                id => $"Blog|{id}",
                id => id.StartsWith("Blog|") ? id.Substring("Blog|".Length) : id);

            // EF Core 9 Cosmos provider throws on HasIndex (Cosmos auto-indexes
            // all properties). Removed the previous HasIndex(b => b.Name) call.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

